+fn run_tensor_binary_conformance_with_fixture(
+    config: &HarnessConfig,
+    mode: ExecutionMode,
+    fixture: &TensorBinaryFixtureFile,
+) -> Result<(HarnessReport, Vec<TensorBinaryCaseReport>), String> {
