+fn vec_within(actual: &[f64], expected: &[f64], tolerance: f64) -> bool {
+    actual.len() == expected.len()
+        && actual
+            .iter()
+            .zip(expected.iter())
+            .all(|(actual, expected)| within(*actual, *expected, tolerance))
+}
